import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';
import '../styles/AdminDashboard.css';

const AdminDashboard = () => {
  const [stats, setStats] = useState({
    documentCount: 0,
    vectorCount: 0,
    folderCount: 0
  });
  const [folders, setFolders] = useState([]);
  const [folderPath, setFolderPath] = useState('');
  const [isMonitoring, setIsMonitoring] = useState(false);
  const [monitorInterval, setMonitorInterval] = useState(30);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [embedCode, setEmbedCode] = useState('');
  const [showEmbedCode, setShowEmbedCode] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    fetchStats();
    fetchFolders();
    fetchEmbedCode();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleLogout = async () => {
    try {
      const refreshToken = localStorage.getItem('refreshToken');
      await api.post('/logout', { refresh_token: refreshToken });
    } catch (error) {
      console.error('Logout error:', error);
    } finally {
      // Clear local storage and redirect
      localStorage.clear();
      navigate('/admin/login');
    }
  };

  const fetchStats = async () => {
    try {
      // Get vector store stats using api service (auto-adds token)
      const vectorResponse = await api.get('/admin/vector-store-stats');

      setStats({
        documentCount: vectorResponse.data.document_count || 0,
        folderCount: vectorResponse.data.folderCount || 0,
        vectorCount: vectorResponse.data.vector_count || 0
      });
    } catch (err) {
      if (err.response && err.response.status === 401) {
        navigate('/admin/login');
      } else {
        setError('Failed to fetch stats');
      }
    }
  };

  const fetchFolders = async () => {
    try {
      const response = await api.get('/admin/list-monitored-folders');
      setFolders(response.data.folders || []);
    } catch (err) {
      if (err.response && err.response.status === 401) {
        navigate('/admin/login');
      } else {
        setError('Failed to fetch monitored folders');
      }
    }
  };

  const handleAddFolder = async () => {
    if (!folderPath) {
      setError('Please enter a folder path');
      return;
    }

    setIsLoading(true);
    setError('');

    try {
      let endpoint = isMonitoring ? '/admin/monitor-drive-folder' : '/admin/process-drive-folder';

      const payload = {
        folder_link: folderPath
      };

      // Add interval_minutes parameter if monitoring is enabled
      if (isMonitoring) {
        payload.interval_minutes = monitorInterval;
      }

      const response = await api.post(endpoint, payload);

      setFolderPath('');
      setIsMonitoring(false);
      fetchStats();
      fetchFolders();
      alert(response.data.message || 'Folder added successfully');
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to process folder');
      console.error('Error adding folder:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleClearVectorStore = async () => {
    if (!window.confirm('Are you sure you want to clear the vector store? This action cannot be undone.')) {
      return;
    }

    setIsLoading(true);
    setError('');

    try {
      await api.post('/admin/clear-vector-store', {});
      fetchStats();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to clear vector store');
    } finally {
      setIsLoading(false);
    }
  };

  const handleSyncAllFolders = async () => {
    setIsLoading(true);
    setError('');

    try {
      const response = await api.post('/admin/sync-all-folders-now', {});

      fetchFolders();
      fetchStats();

      if (response.data.success) {
        const { folder_count, total_processed_count } = response.data;
        alert(`Synced ${folder_count} folders. Processed: ${total_processed_count}`);
      } else {
        setError(response.data.message || 'Failed to sync all folders');
        alert(response.data.message || 'Failed to sync all folders');
      }
    } catch (err) {
      const errorMessage = err.response?.data?.message || err.response?.data?.error || 'Failed to sync all folders';
      setError(errorMessage);
      alert(errorMessage);
      console.error('Error syncing all folders:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSyncFolder = async (folderId) => {
    setIsLoading(true);
    setError('');

    try {
      const response = await api.post('/admin/sync-folder-now', { 
        folder_id: folderId 
      });

      fetchFolders();
      fetchStats();

      if (response.data.success) {
        const { documents_processed, documents_updated } = response.data;
        alert(`Folder synced successfully. Processed: ${documents_processed}, Updated: ${documents_updated}`);
      } else {
        setError(response.data.message || 'Failed to sync folder');
        alert(response.data.message || 'Failed to sync folder');
      }
    } catch (err) {
      const errorMessage = err.response?.data?.message || err.response?.data?.error || 'Failed to sync folder';
      setError(errorMessage);
      alert(errorMessage);
      console.error('Error syncing folder:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleStopMonitoring = async (folderId) => {
    if (!window.confirm('Are you sure you want to stop monitoring this folder?')) {
      return;
    }

    setIsLoading(true);
    setError('');

    try {
      const response = await api.post('/admin/stop-monitoring-folder', {
        folder_id: folderId
      });

      // Remove the folder from the local state immediately
      setFolders(prevFolders => prevFolders.filter(folder => folder.folder_id !== folderId));

      // Then fetch the updated list from the server
      fetchFolders();
      fetchStats();

      alert(response.data.message || 'Folder monitoring stopped successfully');
    } catch (err) {
      setError(err.response?.data?.message || err.response?.data?.error || 'Failed to stop monitoring folder');
      console.error('Error stopping monitoring:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateWidgetKey = async () => {
    setIsLoading(true);
    setError('');

    try {
      const response = await api.post('/admin/generate-widget-key', {});

      if (response.data.success) {
        // Fetch the embed code after generating the key
        fetchEmbedCode();
        alert('Widget API key generated successfully!');
      } else {
        setError('Failed to generate widget key');
      }
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to generate widget key');
      console.error('Error generating widget key:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchEmbedCode = async () => {
    try {
      const response = await api.get('/admin/get-widget-code');

      if (response.data.success) {
        setEmbedCode(response.data.embed_code);
        setShowEmbedCode(true);
      }
    } catch (err) {
      if (err.response && err.response.status === 404) {
        // Widget not configured yet
        setShowEmbedCode(false);
      } else {
        console.error('Error fetching embed code:', err);
      }
    }
  };

  const handleCopyEmbedCode = () => {
    navigator.clipboard.writeText(embedCode);
    alert('Embed code copied to clipboard!');
  };

  return (
    <div className="admin-dashboard">
      <header className="admin-header">
        <h1 className="admin-title">Admin Dashboard</h1>
        <div className="header-buttons">
          <button className="start-chat-button" onClick={() => navigate('/chat')}>Start Chatting with AI</button>
          <button className="logout-button" onClick={handleLogout}>Logout</button>
        </div>
      </header>

      <div className="admin-content">
        {error && <div className="error-message">{error}</div>}

        <section className="dashboard-section">
          <h2 className="section-title">Vector Store Statistics</h2>
          <div className="stats-grid">
            <div className="stat-card">
              <div className="stat-value">{stats.documentCount}</div>
              <div className="stat-label">Documents</div>
            </div>
            <div className="stat-card">
              <div className="stat-value">{stats.vectorCount}</div>
              <div className="stat-label">Vectors</div>
            </div>
            <div className="stat-card">
              <div className="stat-value">{stats.folderCount}</div>
              <div className="stat-label">Monitored Folders</div>
            </div>
          </div>
        </section>

        <section className="dashboard-section">
          <h2 className="section-title">Process Google Drive Folder</h2>
          <div className="form-group">
            <label htmlFor="folderPath">Folder Path:</label>
            <input
              type="text"
              id="folderPath"
              value={folderPath}
              onChange={(e) => setFolderPath(e.target.value)}
              placeholder="Enter Google Drive folder path"
              disabled={isLoading}
            />
          </div>

          <div className="form-group">
            <label>
              <input
                type="checkbox"
                checked={isMonitoring}
                onChange={(e) => setIsMonitoring(e.target.checked)}
                disabled={isLoading}
              />
              Monitor for changes
            </label>
            <span className="helper-text">
              Check this box to automatically sync this folder at regular intervals
            </span>
          </div>

          {isMonitoring && (
            <div className="form-group">
              <label htmlFor="interval">Monitor interval (minutes):</label>
              <input
                type="number"
                id="interval"
                value={monitorInterval}
                onChange={(e) => setMonitorInterval(parseInt(e.target.value) || 30)}
                min="1"
                max="1440"
                disabled={isLoading}
              />
              <span className="helper-text">
                Set how often the folder should be checked for new documents (1-1440 minutes)
              </span>
            </div>
          )}

          <button 
            className="action-button primary-button"
            onClick={handleAddFolder}
            disabled={isLoading || !folderPath}
          >
            {isLoading ? 'Processing...' : 'Process Folder'}
          </button>
        </section>

        <section className="dashboard-section">
          <h2 className="section-title">Monitored Folders</h2>
          {folders.length > 0 && (
            <button 
              className="action-button primary-button"
              onClick={handleSyncAllFolders}
              disabled={isLoading}
            >
              Sync All Folders
            </button>
          )}
          {folders.length === 0 ? (
            <p>No folders are currently being monitored.</p>
          ) : (
            <ul className="folder-list">
              {folders.map((folder, index) => (
                <li key={index} className="folder-item">
                  <div>
                    <strong>Folder Link:</strong> {folder.folder_link}
                    {folder.interval_minutes && (
                      <div><strong>Monitoring Interval:</strong> {folder.interval_minutes} minutes</div>
                    )}
                    {folder.last_check && (
                      <div><strong>Last Checked:</strong> {new Date(Number(folder.last_check)).toLocaleString()}</div>
                    )}
                    {folder.next_check && (
                      <div><strong>Next Check:</strong> {
                        // Calculate next check time based on last check and interval
                        folder.interval_minutes ? 
                          new Date(Number(folder.last_check) + folder.interval_minutes * 60000).toLocaleString() :
                          new Date(Number(folder.next_check)).toLocaleString()
                      }</div>
                    )}
                    {folder.doc_count !== undefined && (
                      <div><strong>Documents:</strong> {folder.doc_count}</div>
                    )}
                    <div className="folder-actions">
                      <button 
                        className="action-button small-button"
                        onClick={() => handleSyncFolder(folder.folder_id)}
                        disabled={isLoading}
                      >
                        Sync Now
                      </button>
                      <button 
                        className="action-button small-button danger-button"
                        onClick={() => handleStopMonitoring(folder.folder_id)}
                        disabled={isLoading}
                      >
                        Stop Monitoring
                      </button>
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          )}
        </section>

        <section className="dashboard-section">
          <h2 className="section-title">Embed Chat Widget</h2>
          <p className="section-description">
            Embed the AI chat widget on your website to allow visitors to interact with your documents.
          </p>

          {!showEmbedCode ? (
            <div>
              <p>Generate an API key to get started with the chat widget.</p>
              <button 
                className="action-button primary-button"
                onClick={handleGenerateWidgetKey}
                disabled={isLoading}
              >
                Generate Widget API Key
              </button>
            </div>
          ) : (
            <div className="embed-code-container">
              <p><strong>Copy and paste this code into your website's HTML:</strong></p>
              <div className="code-block">
                <pre>{embedCode}</pre>
              </div>
              <div className="embed-actions">
                <button 
                  className="action-button primary-button"
                  onClick={handleCopyEmbedCode}
                >
                  Copy Embed Code
                </button>
                <button 
                  className="action-button secondary-button"
                  onClick={handleGenerateWidgetKey}
                  disabled={isLoading}
                >
                  Regenerate API Key
                </button>
              </div>
              <div className="widget-instructions">
                <h3>How to use:</h3>
                <ol>
                  <li>Copy the embed code above</li>
                  <li>Paste it before the closing <code>&lt;/body&gt;</code> tag in your website's HTML</li>
                  <li>The chat widget will appear in the bottom-right corner of your website</li>
                  <li>Visitors can chat with the AI and get answers based on your uploaded documents</li>
                </ol>
              </div>
            </div>
          )}
        </section>

        <section className="dashboard-section">
          <h2 className="section-title">Maintenance</h2>
          <button 
            className="action-button danger-button"
            onClick={handleClearVectorStore}
            disabled={isLoading}
          >
            Clear Vector Store
          </button>
        </section>
      </div>
    </div>
  );
};

export default AdminDashboard;
